<?php require_once '../config/db.php'; if(!isset($_GET['id'])) redirect('orders.php'); $id=$_GET['id']; $order=$pdo->prepare("SELECT * FROM orders WHERE id=?"); $order->execute([$id]); $order=$order->fetch(); $items=$pdo->prepare("SELECT * FROM order_items WHERE order_id=?"); $items->execute([$id]); $items=$items->fetchAll(); include 'includes/admin_header.php'; ?>
<div class="container-fluid"><div class="row"><?php include 'includes/admin_sidebar.php'; ?><main class="col-md-9"><h2>Order Details: <?php echo $order['order_number']; ?></h2><p>Customer: <?php echo $order['customer_name']; ?><br>Phone: <?php echo $order['customer_phone']; ?><br>Address: <?php echo $order['customer_address']; ?></p><table class="table"><tr><th>Product</th><th>Qty</th><th>Price</th><th>Subtotal</th></tr><?php foreach($items as $i){ echo "<tr><td>{$i['product_name']}</td><td>{$i['quantity']}</td><td>₦".number_format($i['price'],2)."</td><td>₦".number_format($i['price']*$i['quantity'],2)."</td></tr>"; } ?></table><p><strong>Total: ₦<?php echo number_format($order['order_total'],2); ?></strong></p><a href="orders.php" class="btn btn-secondary">Back</a></main></div></div>
<?php include 'includes/admin_footer.php'; ?>